// Enhanced Rate-Limited Webhook Parser - Max 30 posts per day
// Post URL validation completely removed

// Get both the HTTP response data and original webhook data
const httpResponseData = $input.item.json; // Profile data from HTTP request
const originalWebhookData = $input.first().json; // Original webhook from first node

// Merge them for processing
const webhookData = {
  ...originalWebhookData,
  enrichedProfile: httpResponseData
};

// Get current date for daily tracking
const today = new Date().toISOString().split('T')[0]; // Format: YYYY-MM-DD
const now = new Date();

// JSONBin.io configuration
const binId = '68c106bc43b1c97be93d5662';
const apiKey = 'token';

// Extract posted date for age validation only
const postedDateStr = originalWebhookData.body?.posted_date;

// Basic validation checks (removed business hours and post URL validation)
const isWeekday = new Date().getDay() >= 1 && new Date().getDay() <= 5;

// Check post age (must be within 14 days)
let isPostFresh = false;
let postAgeInDays = null;

if (postedDateStr) {
  const postedDate = new Date(postedDateStr);
  const daysDifference = Math.floor((now - postedDate) / (1000 * 60 * 60 * 24));
  postAgeInDays = daysDifference;
  isPostFresh = daysDifference <= 14;
}

let shouldProcess = false;
let processingStatus = {
  shouldProcess: false,
  reason: 'Checking daily limits...',
  currentTime: now.toISOString(),
  weekday: isWeekday,
  postAge: postAgeInDays,
  postFresh: isPostFresh,
  dailyCount: 0,
  dailyLimit: 30,
  alreadyProcessed: false
};

// Only proceed with API calls if basic conditions are met (removed post URL check)
if (isWeekday && isPostFresh) {
  try {
    // Get current data from JSONBin
    const getResponse = await fetch(`https://api.jsonbin.io/v3/b/${binId}`, {
      method: 'GET',
      headers: {
        'X-Master-Key': apiKey,
        'Content-Type': 'application/json'
      }
    });

    if (getResponse.ok) {
      const data = await getResponse.json();
      const binData = data.record || {};

      // Initialize structure if needed
      if (!binData.dailyCounts) binData.dailyCounts = {};
      if (!binData.processedPosts) binData.processedPosts = [];

      const todayCount = binData.dailyCounts[today] || 0;
      processingStatus.dailyCount = todayCount;

      // Simple duplicate check using timestamp (since we removed post URL validation)
      const currentTimestamp = now.getTime();
      const alreadyProcessed = binData.processedPosts.some(entry => 
        Math.abs(new Date(entry.processedTime).getTime() - currentTimestamp) < 60000 // within 1 minute
      );
      processingStatus.alreadyProcessed = alreadyProcessed;

      if (!alreadyProcessed && todayCount < 30) {
        // We can process this signal - increment the counter
        const updatedBinData = {
          ...binData,
          dailyCounts: {
            ...binData.dailyCounts,
            [today]: todayCount + 1
          },
          processedPosts: [
            ...binData.processedPosts,
            {
              processedDate: today,
              processedTime: now.toISOString()
            }
          ]
        };

        // Clean up old data
        const thirtyDaysAgo = new Date();
        thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

        // Remove old daily counts
        Object.keys(updatedBinData.dailyCounts).forEach(date => {
          if (new Date(date) < thirtyDaysAgo) {
            delete updatedBinData.dailyCounts[date];
          }
        });

        // Remove old processed posts (keep only last 60 days)
        const sixtyDaysAgo = new Date();
        sixtyDaysAgo.setDate(sixtyDaysAgo.getDate() - 60);
        updatedBinData.processedPosts = updatedBinData.processedPosts.filter(entry => 
          new Date(entry.processedDate) >= sixtyDaysAgo
        );

        // Update the bin with new data
        const updateResponse = await fetch(`https://api.jsonbin.io/v3/b/${binId}`, {
          method: 'PUT',
          headers: {
            'X-Master-Key': apiKey,
            'Content-Type': 'application/json'
          },
          body: JSON.stringify(updatedBinData)
        });

        if (updateResponse.ok) {
          shouldProcess = true;
          processingStatus.shouldProcess = true;
          processingStatus.reason = `Processed (${todayCount + 1}/30 today)`;
          processingStatus.dailyCount = todayCount + 1;
        } else {
          processingStatus.reason = 'Failed to update tracking data';
        }

      } else {
        if (alreadyProcessed) {
          processingStatus.reason = 'Recently processed - duplicate detected';
        } else {
          processingStatus.reason = `Daily limit reached (${todayCount}/30)`;
        }
      }

    } else {
      processingStatus.reason = 'Failed to check tracking data - API error';
    }

  } catch (error) {
    // If JSONBin fails, fall back to basic time-based limiting
    console.log('JSONBin error, using fallback:', error);
    shouldProcess = true;
    processingStatus.shouldProcess = true;
    processingStatus.reason = 'JSONBin unavailable - proceeding with fallback';
  }

} else {
  // Basic conditions not met
  if (!isWeekday) {
    processingStatus.reason = 'Weekend - skipping';
  } else if (!isPostFresh) {
    processingStatus.reason = `Post too old (${postAgeInDays} days - limit: 30 days)`;
  }
}

// Extract all the main sections from original webhook data
const company = originalWebhookData.body?.company || {};
const prospect = originalWebhookData.body?.prospect || {};
const linkedinEngagement = originalWebhookData.body?.linkedin_engagement || {};
const enrichedEmails = prospect.enriched_email || [];
const enrichedPhones = prospect.enriched_phone || [];

// Get headers from the original webhook
const headers = originalWebhookData.headers || {};



return {
