    linkedinUrl: company.linkedin_url,
    location: company.location,
    logo: company.logo,
    size: company.size,
    linkedinUsername: company.linkedinUsername
  },

  // LinkedIn engagement details from original webhook
  engagement: {
    type: linkedinEngagement.type,
    text: linkedinEngagement.text,
    postText: linkedinEngagement.linkedin_post?.text,
