  const parts = aiResponse.split("\\n\\n");
  // Find the last part that looks like an actual comment (starts with capital letter)
  for (let i = parts.length - 1; i >= 0; i--) {
    const part = parts[i].trim();
    if (part.length > 50 && /^[A-Z]/.test(part)) {
      extractedComment = part;
      break;
    }
  }
}
// Method 3: Look for content after the last colon followed by newline
else {
  const colonSplit = aiResponse.split(/:\s*\\n/);
  if (colonSplit.length > 1) {
    extractedComment = colonSplit[colonSplit.length - 1].trim();
  }
}

// If none of the above worked, try to find the actual comment by looking for common LinkedIn response starters
if (!extractedComment || extractedComment.length < 20) {
  const responseStarters = [
    /\b(Spot on|Great point|Excellent|Thanks|Absolutely|You're right|Love this|Interesting|Good question)/i
  ];

  for (let starter of responseStarters) {
    const match = aiResponse.match(starter);
    if (match) {
      const startIndex = match.index;
      extractedComment = aiResponse.substring(startIndex).trim();
      break;
    }
  }
}

// Clean up the extracted comment
if (extractedComment) {
  extractedComment = extractedComment
    .replace(/\\n/g, ' ')           // Replace literal \n with spaces
    .replace(/\s+/g, ' ')           // Normalize multiple spaces
    .replace(/^["'\s]+/, '')        // Remove leading quotes/spaces  
    .replace(/["'\s]+$/, '')        // Remove trailing quotes/spaces
    .trim();

  // Remove any remaining system text that might have slipped through
  extractedComment = extractedComment
    .replace(/^Based on.*?response:\s*/i, '')
    .replace(/^Here's.*?response:\s*/i, '')
    .replace(/^I'll.*?response:\s*/i, '')
    .trim();
}

// Final fallback - if we still don't have good content
if (!extractedComment || extractedComment.length < 20) {
  extractedComment = "Error: Could not extract LinkedIn response";
}

// Ensure it's not too long for LinkedIn (max 3000 chars, but keeping shorter)
