    .replace(/\\n/g, '\n');        // Convert escaped single newlines

  const parts = normalizedText.split(/\n\n+/);

  // Find the longest substantial part that looks like a comment
  let bestPart = "";
  let bestLength = 0;

  for (let part of parts) {
    const cleaned = part.trim();
    // Skip parts that look like instructions or meta-text
    if (cleaned.length > bestLength && 
        !cleaned.match(/^(Here'?s?|Based on|I'll|Let me|This)/i) &&
        cleaned.length > 50) {
      bestPart = cleaned;
      bestLength = cleaned.length;
    }
  }

  if (bestPart) {
    extractedComment = bestPart;
  }
}

