if (!extractedComment || extractedComment.length < 50) {
  const commentStarters = [
    /\b(Spot on|Great point|Excellent|Thanks|Thank you|Absolutely|You're right|Love this|Interesting|Good question|Fascinating|Insightful|Well said|Couldn't agree more|This resonates|Appreciate|Congrats|Congratulations|I've found|In my experience|From my perspective|What stands out)/i
  ];

  for (let starter of commentStarters) {
    const match = responseText.match(starter);
    if (match && match.index !== undefined) {
      // Extract from the match to the end
      const possibleComment = responseText.substring(match.index);
      // But stop at any obvious AI meta-text
      const endMatch = possibleComment.match(/\n\n(?:Is there|Would you|Let me know|Feel free)/i);
      if (endMatch) {
        extractedComment = possibleComment.substring(0, endMatch.index).trim();
      } else {
        extractedComment = possibleComment.trim();
      }
      break;
    }
  }
}

// Method 4: If still nothing, try to extract the most comment-like paragraph
if (!extractedComment || extractedComment.length < 30) {
  const normalizedText = responseText
    .replace(/\\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n');

  const paragraphs = normalizedText.split(/\n+/);

  // Find the first substantial paragraph that doesn't look like AI instructions
  for (let para of paragraphs) {
    const cleaned = para.trim();
    if (cleaned.length > 50 && 
        !cleaned.match(/^(Here'?s?|Based on|I'll|Let me|This is|I've|Below)/i) &&
        !cleaned.includes('response:') &&
        !cleaned.includes('comment:')) {
      extractedComment = cleaned;
      break;
    }
  }
}

// Clean up the extracted comment
if (extractedComment) {
  extractedComment = extractedComment
    // Remove any quotation marks that might wrap the entire response
    .replace(/^["'`]+|["'`]+$/g, '')
    // Clean up whitespace
    .replace(/\n{2,}/g, '\n\n')     // Normalize multiple newlines to double
    .replace(/[ \t]+/g, ' ')         // Normalize spaces and tabs
    .trim();

  // Remove common AI prefixes that might have slipped through
  const prefixPatterns = [
    /^(?:Here'?s?|Based on|I'll craft|Let me create|This is).*?(?:response|comment).*?[:\n]+/i,
    /^Response[:\s]+/i,
    /^Comment[:\s]+/i,
    /^LinkedIn Comment[:\s]+/i
  ];

  for (let pattern of prefixPatterns) {
    extractedComment = extractedComment.replace(pattern, '').trim();
  }

  // Remove common AI suffixes
  const suffixPatterns = [
    /\n+(?:Is there|Would you|Let me know|Feel free|I hope this|This comment).*$/i,
    /\n+(?:---+|___+|\*\*\*+).*$/,  // Remove separators and anything after
  ];

  for (let pattern of suffixPatterns) {
    extractedComment = extractedComment.replace(pattern, '').trim();
  }
}

// Final validation and fallback
if (!extractedComment || extractedComment.length < 20) {
  // Last resort: just clean up the original response
  extractedComment = responseText
    .replace(/\\n/g, ' ')
    .replace(/\s+/g, ' ')
    .substring(0, 500)
