// Ensure it's not too long for LinkedIn (max ~3000 chars, but keep it reasonable)
if (extractedComment.length > 1200 && !extractedComment.includes("Error:")) {
  // Try to find a natural breaking point
  const sentences = extractedComment.match(/[^.!?]+[.!?]+/g) || [extractedComment];
  let truncated = "";

  for (let sentence of sentences) {
    if ((truncated + sentence).length < 1150) {
      truncated += sentence;
    } else {
      // Add the sentence partially if we have room
      if (truncated.length < 1000) {
        const remaining = 1150 - truncated.length;
        truncated += sentence.substring(0, remaining) + "...";
      }
      break;
    }
  }

  extractedComment = truncated.trim() || extractedComment.substring(0, 1150) + "...";
}

// Format for better readability (preserve intentional line breaks)
extractedComment = extractedComment
  .replace(/\n\n+/g, '\n\n')  // Keep paragraph breaks as double newlines
  .replace(/([.!?])\s*\n(?!\n)/g, '$1 ')  // Single newlines after sentences become spaces
  .trim();

